cd "/Users/hsin-hsinyuan/Documents/Claude/Projects/Moonie V/hsin-hsin-yuan-portfolio-edit" && node --input-type=module -e "
import { loadSiteData, loadWorks, renderPage } from './scripts/build-site.mjs';
import { join } from 'node:path';
const root = process.cwd();
const site = loadSiteData(root);
const works = loadWorks(join(root, 'content/works'));
const html = renderPage({ lang: 'en', site, works });
const ids = [...html.matchAll(/id=\"([^\"]+)\"/g)].map(m => m[1]);
const hrefs = [...html.matchAll(/href=\"#([^\"]+)\"/g)].map(m => m[1]);
console.log('IDs:', ids.join(', '));
console.log('Anchor hrefs:', hrefs.join(', '));
console.log('Broken anchors:', hrefs.filter(h => !ids.includes(h)).join(', ') || '(none)');
console.log('work-panel count:', (html.match(/class=\"work-panel/g)||[]).length);
console.log('foreground img present:', html.includes('hero-portrait-foreground'));
const html2 = renderPage({ lang: 'en', site: { ...site, media: { hero: { ...site.media.hero, foreground: '/assets/portfolio/x.png' } } }, works });
console.log('foreground img when set:', html2.includes('hero-portrait-foreground'));
console.log('strip cards:', (html.match(/watch-loop-card/g)||[]).length);
"
